('ar', 'ir-pr', '{"ir_pr":{"hero":{"title":"علاقات","title_highlight":"المستثمرين","description":"منصة موحدة لعلاقات المستثمرين والعلاقات العامة لتضخيم سردك المؤسسي.","cta_button":"ابدأ حملتك"},"key_features":{"title":"منصة IR/PR متكاملة","features":[{"title":"توزيع البيانات الصحفية","description":"شبكة توزيع عالمية تصل إلى الصحفيين والمستثمرين.","icon":"Globe"},{"title":"استهداف المستثمرين","description":"تحديد واستهداف المستثمرين بالذكاء الاصطناعي.","icon":"Target"},{"title":"العلاقات الإعلامية","description":"بناء وإدارة علاقات الصحفيين.","icon":"Users"},{"title":"إنشاء المحتوى","description":"إنشاء بمساعدة AI للبيانات الصحفية.","icon":"FileText"},{"title":"إدارة الفعاليات","description":"أيام المستثمرين ومكالمات الأرباح.","icon":"Calendar"},{"title":"إدارة السمعة","description":"مراقبة وحماية سمعتك المؤسسية.","icon":"Shield"}]},"benefits":{"title":"لماذا AmplifiX IR/PR","items":[{"title":"منصة موحدة","description":"منصة واحدة لجميع أنشطة IR وPR."},{"title":"وصول عالمي","description":"توزيع إلى أكثر من 170 دولة."},{"title":"تأثير قابل للقياس","description":"تتبع كل تفاعل مع تحليلات مفصلة."},{"title":"دعم الخبراء","description":"متخصصون مخصصون في IR/PR."}]}}}'),
('ro', 'ir-pr', '{"ir_pr":{"hero":{"title":"Relații cu","title_highlight":"Investitorii","description":"Platformă unificată de relații cu investitorii și relații publice.","cta_button":"Începe Campania"},"key_features":{"title":"Platformă Completă IR/PR","features":[{"title":"Distribuție Comunicate","description":"Rețea de distribuție globală.","icon":"Globe"},{"title":"Targetare Investitori","description":"Identificare și targetare bazată pe AI.","icon":"Target"},{"title":"Relații Media","description":"Construiește relațiile cu jurnaliștii.","icon":"Users"},{"title":"Creare Conținut","description":"Creare asistată de AI.","icon":"FileText"},{"title":"Management Evenimente","description":"Zile ale investitorilor și apeluri.","icon":"Calendar"},{"title":"Management Reputație","description":"Monitorizează reputația corporativă.","icon":"Shield"}]},"benefits":{"title":"De Ce AmplifiX IR/PR","items":[{"title":"Platformă Unificată","description":"O singură platformă pentru toate activitățile."},{"title":"Acoperire Globală","description":"Distribuție în peste 170 de țări."},{"title":"Impact Măsurabil","description":"Urmărește fiecare interacțiune."},{"title":"Suport Expert","description":"Specialiști dedicați IR/PR."}]}}}'),
('th', 'ir-pr', '{"ir_pr":{"hero":{"title":"ความสัมพันธ์","title_highlight":"นักลงทุน","description":"แพลตฟอร์มความสัมพันธ์นักลงทุนและประชาสัมพันธ์แบบรวม","cta_button":"เริ่มแคมเปญ"},"key_features":{"title":"แพลตฟอร์ม IR/PR ครบวงจร","features":[{"title":"การกระจายข่าว","description":"เครือข่ายการกระจายทั่วโลก","icon":"Globe"},{"title":"การกำหนดเป้าหมายนักลงทุน","description":"การระบุและกำหนดเป้าหมายด้วย AI","icon":"Target"},{"title":"ความสัมพันธ์สื่อ","description":"สร้างความสัมพันธ์กับนักข่าว","icon":"Users"},{"title":"การสร้างเนื้อหา","description":"การสร้างด้วยความช่วยเหลือของ AI","icon":"FileText"},{"title":"การจัดการกิจกรรม","description":"วันนักลงทุนและการประชุม","icon":"Calendar"},{"title":"การจัดการชื่อเสียง","description":"ติดตามและปกป้องชื่อเสียง","icon":"Shield"}]},"benefits":{"title":"ทำไมต้อง AmplifiX IR/PR","items":[{"title":"แพลตฟอร์มรวม","description":"แพลตฟอร์มเดียวสำหรับกิจกรรมทั้งหมด"},{"title":"การเข้าถึงทั่วโลก","description":"การกระจายไปยังกว่า 170 ประเทศ"},{"title":"ผลกระทบที่วัดได้","description":"ติดตามทุกการมีส่วนร่วม"},{"title":"การสนับสนุนจากผู้เชี่ยวชาญ","description":"ผู้เชี่ยวชาญ IR/PR ที่ทุ่มเท"}]}}}'),
('tr', 'ir-pr', '{"ir_pr":{"hero":{"title":"Yatırımcı","title_highlight":"İlişkileri","description":"Birleşik yatırımcı ilişkileri ve halkla ilişkiler platformu.","cta_button":"Kampanyanızı Başlatın"},"key_features":{"title":"Kapsamlı IR/PR Platformu","features":[{"title":"Basın Bülteni Dağıtımı","description":"Küresel dağıtım ağı.","icon":"Globe"},{"title":"Yatırımcı Hedefleme","description":"AI destekli yatırımcı tanımlama.","icon":"Target"},{"title":"Medya İlişkileri","description":"Gazeteci ilişkilerini yönetin.","icon":"Users"},{"title":"İçerik Oluşturma","description":"AI destekli oluşturma.","icon":"FileText"},{"title":"Etkinlik Yönetimi","description":"Yatırımcı günleri ve çağrılar.","icon":"Calendar"},{"title":"İtibar Yönetimi","description":"Kurumsal itibarınızı koruyun.","icon":"Shield"}]},"benefits":{"title":"Neden AmplifiX IR/PR","items":[{"title":"Birleşik Platform","description":"Tüm faaliyetler için tek platform."},{"title":"Küresel Erişim","description":"170+ ülkeye dağıtım."},{"title":"Ölçülebilir Etki","description":"Her etkileşimi takip edin."},{"title":"Uzman Desteği","description":"Özel IR/PR uzmanları."}]}}}'),
('uk', 'ir-pr', '{"ir_pr":{"hero":{"title":"Зв''язки з","title_highlight":"Інвесторами","description":"Уніфікована платформа для відносин з інвесторами та зв''язків з громадськістю.","cta_button":"Почати Кампанію"},"key_features":{"title":"Комплексна Платформа IR/PR","features":[{"title":"Розповсюдження Прес-релізів","description":"Глобальна мережа розповсюдження.","icon":"Globe"},{"title":"Таргетування Інвесторів","description":"Визначення та таргетування на основі AI.","icon":"Target"},{"title":"Медіа-відносини","description":"Будуйте відносини з журналістами.","icon":"Users"},{"title":"Створення Контенту","description":"Створення за допомогою AI.","icon":"FileText"},{"title":"Управління Подіями","description":"Дні інвесторів та дзвінки.","icon":"Calendar"},{"title":"Управління Репутацією","description":"Моніторинг репутації.","icon":"Shield"}]},"benefits":{"title":"Чому AmplifiX IR/PR","items":[{"title":"Уніфікована Платформа","description":"Єдина платформа для всіх активностей."},{"title":"Глобальне Охоплення","description":"Розповсюдження в 170+ країнах."},{"title":"Вимірюваний Вплив","description":"Відстежуйте кожну взаємодію."},{"title":"Експертна Підтримка","description":"Виділені спеціалісти IR/PR."}]}}}')
