('ar', 'fundraising', '{"fundraising":{"hero":{"title":"حلول جمع التمويل بالذكاء الاصطناعي","description":"تسريع عملية جمع التمويل مع استهداف المستثمرين الذكي والتواصل الآلي.","cta_button":"تحسين جمع التمويل"},"key_features":{"title":"منصة جمع التمويل الكاملة","features":[{"title":"مطابقة المستثمرين الذكية","description":"قاعدة بيانات AI لأكثر من 10,000 مستثمر.","icon":"Target"},{"title":"تحسين العرض التقديمي","description":"تحليل AI للعروض الناجحة.","icon":"DollarSign"},{"title":"التواصل الآلي","description":"حملات بريد إلكتروني مخصصة.","icon":"Users"},{"title":"إدارة غرفة الصفقات","description":"غرف بيانات آمنة مع تتبع.","icon":"BarChart3"},{"title":"ذكاء السوق","description":"اتجاهات التمويل في الوقت الفعلي.","icon":"Lightbulb"},{"title":"تحليل ورقة الشروط","description":"مقارنة وتوجيه التفاوض.","icon":"CheckCircle"}]},"process":{"title":"عملية جمع التمويل المبسطة","steps":[{"step":1,"title":"الاستراتيجية والإعداد","description":"تحديد الأهداف وتحسين المواد."},{"step":2,"title":"التواصل مع المستثمرين","description":"إطلاق حملات تواصل آلية."},{"step":3,"title":"إدارة الاجتماعات","description":"جدولة وتتبع الاجتماعات."},{"step":4,"title":"العناية الواجبة","description":"إدارة غرف البيانات الآمنة."},{"step":5,"title":"التفاوض على الشروط","description":"مقارنة أوراق الشروط والتفاوض."}]}}}'),
('ro', 'fundraising', '{"fundraising":{"hero":{"title":"Soluții de Fundraising cu AI","description":"Accelerează procesul de fundraising cu targetare inteligentă.","cta_button":"Optimizează Fundraising-ul"},"key_features":{"title":"Platformă Completă de Fundraising","features":[{"title":"Potrivire Investitori Inteligentă","description":"Bază de date AI cu 10,000+ investitori.","icon":"Target"},{"title":"Optimizare Pitch Deck","description":"Analiză AI a pitch deck-urilor.","icon":"DollarSign"},{"title":"Outreach Automatizat","description":"Campanii de email personalizate.","icon":"Users"},{"title":"Management Deal Room","description":"Camere de date sigure.","icon":"BarChart3"},{"title":"Inteligență de Piață","description":"Tendințe de finanțare în timp real.","icon":"Lightbulb"},{"title":"Analiză Term Sheet","description":"Comparare și ghidare negociere.","icon":"CheckCircle"}]},"process":{"title":"Proces de Fundraising Simplificat","steps":[{"step":1,"title":"Strategie și Pregătire","description":"Definește obiectivele și optimizează materialele."},{"step":2,"title":"Outreach Investitori","description":"Lansează campanii automate."},{"step":3,"title":"Management Întâlniri","description":"Programează și urmărește întâlnirile."},{"step":4,"title":"Due Diligence","description":"Gestionează camerele de date sigure."},{"step":5,"title":"Negociere Termeni","description":"Compară și negociază."}]}}}'),
('th', 'fundraising', '{"fundraising":{"hero":{"title":"โซลูชันระดมทุนด้วย AI","description":"เร่งกระบวนการระดมทุนด้วยการกำหนดเป้าหมายอัจฉริยะ","cta_button":"ปรับปรุงการระดมทุน"},"key_features":{"title":"แพลตฟอร์มระดมทุนครบวงจร","features":[{"title":"การจับคู่นักลงทุนอัจฉริยะ","description":"ฐานข้อมูล AI ของนักลงทุนกว่า 10,000 ราย","icon":"Target"},{"title":"การปรับปรุง Pitch Deck","description":"การวิเคราะห์ AI ของ pitch deck","icon":"DollarSign"},{"title":"การติดต่อแบบอัตโนมัติ","description":"แคมเปญอีเมลส่วนบุคคล","icon":"Users"},{"title":"การจัดการ Deal Room","description":"ห้องข้อมูลที่ปลอดภัย","icon":"BarChart3"},{"title":"ข่าวกรองตลาด","description":"แนวโน้มการระดมทุนแบบเรียลไทม์","icon":"Lightbulb"},{"title":"การวิเคราะห์ Term Sheet","description":"การเปรียบเทียบและคำแนะนำ","icon":"CheckCircle"}]},"process":{"title":"กระบวนการระดมทุนที่คล่องตัว","steps":[{"step":1,"title":"กลยุทธ์และการเตรียมการ","description":"กำหนดเป้าหมายและปรับปรุงเอกสาร"},{"step":2,"title":"การติดต่อนักลงทุน","description":"เปิดตัวแคมเปญอัตโนมัติ"},{"step":3,"title":"การจัดการประชุม","description":"กำหนดเวลาและติดตามการประชุม"},{"step":4,"title":"การตรวจสอบสถานะ","description":"จัดการห้องข้อมูลที่ปลอดภัย"},{"step":5,"title":"การเจรจาเงื่อนไข","description":"เปรียบเทียบและเจรจา"}]}}}'),
('tr', 'fundraising', '{"fundraising":{"hero":{"title":"AI Destekli Fon Toplama Çözümleri","description":"Akıllı hedefleme ile fon toplama sürecinizi hızlandırın.","cta_button":"Fon Toplamanızı Optimize Edin"},"key_features":{"title":"Kapsamlı Fon Toplama Platformu","features":[{"title":"Akıllı Yatırımcı Eşleştirme","description":"10,000+ yatırımcı AI veritabanı.","icon":"Target"},{"title":"Pitch Deck Optimizasyonu","description":"Başarılı pitch deck AI analizi.","icon":"DollarSign"},{"title":"Otomatik Erişim","description":"Kişiselleştirilmiş e-posta kampanyaları.","icon":"Users"},{"title":"Deal Room Yönetimi","description":"Güvenli veri odaları.","icon":"BarChart3"},{"title":"Piyasa İstihbaratı","description":"Gerçek zamanlı finansman trendleri.","icon":"Lightbulb"},{"title":"Term Sheet Analizi","description":"Karşılaştırma ve müzakere rehberliği.","icon":"CheckCircle"}]},"process":{"title":"Basitleştirilmiş Fon Toplama Süreci","steps":[{"step":1,"title":"Strateji ve Hazırlık","description":"Hedefleri tanımlayın ve materyalleri optimize edin."},{"step":2,"title":"Yatırımcı Erişimi","description":"Otomatik kampanyalar başlatın."},{"step":3,"title":"Toplantı Yönetimi","description":"Toplantıları planlayın ve takip edin."},{"step":4,"title":"Due Diligence","description":"Güvenli veri odalarını yönetin."},{"step":5,"title":"Şart Müzakeresi","description":"Karşılaştırın ve müzakere edin."}]}}}'),
('uk', 'fundraising', '{"fundraising":{"hero":{"title":"AI-Рішення для Залучення Коштів","description":"Прискорюйте процес залучення коштів з інтелектуальним таргетуванням.","cta_button":"Оптимізуйте Залучення Коштів"},"key_features":{"title":"Комплексна Платформа Залучення Коштів","features":[{"title":"Інтелектуальне Зіставлення Інвесторів","description":"AI база даних 10,000+ інвесторів.","icon":"Target"},{"title":"Оптимізація Pitch Deck","description":"AI аналіз успішних презентацій.","icon":"DollarSign"},{"title":"Автоматизований Охоплення","description":"Персоналізовані email кампанії.","icon":"Users"},{"title":"Управління Deal Room","description":"Захищені кімнати даних.","icon":"BarChart3"},{"title":"Ринкова Розвідка","description":"Тренди фінансування в реальному часі.","icon":"Lightbulb"},{"title":"Аналіз Term Sheet","description":"Порівняння та керівництво переговорами.","icon":"CheckCircle"}]},"process":{"title":"Спрощений Процес Залучення Коштів","steps":[{"step":1,"title":"Стратегія та Підготовка","description":"Визначте цілі та оптимізуйте матеріали."},{"step":2,"title":"Охоплення Інвесторів","description":"Запустіть автоматизовані кампанії."},{"step":3,"title":"Управління Зустрічами","description":"Плануйте та відстежуйте зустрічі."},{"step":4,"title":"Due Diligence","description":"Керуйте захищеними кімнатами даних."},{"step":5,"title":"Переговори щодо Умов","description":"Порівнюйте та ведіть переговори."}]}}}')
